mapper.select:
SELECT a.p_sNo, a.coupon_price, a.coupon_id, a.otype, b.id, b.r_sNo, b.user_id, b.p_id, b.p_name, b.p_price, b.num, b.r_status, b.sid, b.size, c.imgurl, a.otype, a.ptcode, c.product_class, d.brand_name, e.costprice, e.price FROM lkt_order a left join lkt_order_details b on a.sno = b.r_sNo left join lkt_product_list c on b.p_id=c.id left join lkt_brand_class d on d.brand_id = c.brand_id left join lkt_configure e on b.sid=e.id where a.store_id = #{store_id}
and a.sNo = #{sNo}
and a.status = #{status}

select a.sNo, a.z_price, a.allow, a.status, a.pay, a.consumer_money, a.extraction_code,
a.extraction_code_img, a.mch_id, b.id detailId, b.express_id, b.after_discount, b.freight,a.self_lifting,
b.p_id, b.num, b.p_price,
b.sid,a.add_time,b.arrive_time,b.supplier_settlement,p.gongyingshang,a.otype,a.currency_code,a.currency_symbol,a.exchange_rate
from lkt_order as a
left join lkt_order_details as b on a.sNo = b.r_sNo
left join lkt_product_list p on b.p_id = p.id
where a.store_id = #{store_id}

    and a.recycle=#{recycle}
    and a.recycle != 1

and a.id = #{id}
and b.id = #{detailId}
and a.mch_id like CONCAT('%,',#{mch_id},',%')
and a.extraction_code like CONCAT('%',#{extraction_code},'%')
and b.r_status = #{r_status}
and b.settlement_type = #{settlement_type}
and a.otype = #{orderType}

