SELECT
DATE_FORMAT(a.add_time, '%Y-%m-%d') AS r_date,
COUNT(*) AS num,
SUM(a.z_price) AS z_price,
COUNT(CASE WHEN a.`status` IN (1, 2, 5, 7) THEN 1 END) AS yx_num,
SUM(CASE WHEN a.`status` IN (1, 2, 5, 7) THEN a.z_price ELSE 0 END) AS yx_amt
FROM lkt_order a
WHERE a.store_id = 1
AND a.recycle = 0


        #{status,jdbcType=INTEGER}


and a.z_price > #{priceGt}


        #{status,jdbcType=INTEGER}


and a.add_time  >=  #{startDate}
and a.add_time  <=  #{endDate}
GROUP BY r_date

    LIMIT #{limit}


    group by r_date

