SELECT IFNULL(SUM(a.z_price), 0) AS amount, ANY_VALUE(m_sub.name) AS name FROM lkt_order a INNER JOIN ( SELECT r_sNo, name, id FROM ( SELECT d.r_sNo, m.name, m.id, ROW_NUMBER() OVER (PARTITION BY d.r_sNo ORDER BY d.r_sNo) AS rn FROM lkt_order_details d INNER JOIN lkt_product_list b ON d.p_id = b.id INNER JOIN lkt_mch m ON b.mch_id = m.id ) t WHERE rn = 1 ) m_sub ON a.sNo = m_sub.r_sNo
and a.store_id=#{storeid}
and a.add_time >= #{startDate}
AND a.pay_time IS NOT NULL AND a.settlement_status = 1 GROUP BY a.mch_id ORDER BY amount DESC LIMIT 0, 10;

