mapper.select:
SELECT CONCAT(HOUR(add_time), '时') AS time, IFNULL(SUM(z_price), 0) AS value FROM `lkt_order` WHERE store_id = #{storeId} AND recycle = 0
AND mch_id = CONCAT(',',#{mchId},',')
AND add_time >= STR_TO_DATE(#{date}, '%Y-%m-%d') AND add_time <= DATE_ADD(STR_TO_DATE(#{date}, '%Y-%m-%d'), INTERVAL 1 DAY) AND STATUS IN (1, 2, 5, 7) AND pay_time IS NOT NULL GROUP BY HOUR(add_time) ORDER BY HOUR(add_time);
